package genxsolution.vms.vmsbackend.maintenance_management.maintenance_program_template.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program_template.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_program_template.service.MaintenanceProgramTemplateService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-program-templates") public class MaintenanceProgramTemplateController { private final MaintenanceProgramTemplateService service; public MaintenanceProgramTemplateController(MaintenanceProgramTemplateService service){this.service=service;} @GetMapping public List<MaintenanceProgramTemplateResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenanceProgramTemplateResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenanceProgramTemplateResponse create(@RequestBody MaintenanceProgramTemplateUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenanceProgramTemplateResponse update(@PathVariable UUID id,@RequestBody MaintenanceProgramTemplateUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
